package ru.memearena.scout.domain; import jakarta.persistence.*; import java.time.*; import java.util.*;
@Entity @Table(name="user_scout_stats") public class UserScoutStats{ @Id @Column(name="user_id") private UUID userId; @Column(name="scout_points") private long scoutPoints; @Column(name="predictions_count") private long predictionsCount; @Column(name="successful_predictions") private long successfulPredictions; @Column(name="failed_predictions") private long failedPredictions; @Column(name="expired_predictions") private long expiredPredictions; @Column(name="current_success_streak") private int currentSuccessStreak; @Column(name="best_success_streak") private int bestSuccessStreak; @Column(name="last_resolved_prediction_at") private Instant lastResolvedPredictionAt; @Column(name="updated_at") private Instant updatedAt; protected UserScoutStats(){} public UserScoutStats(UUID userId,Instant now){this.userId=userId;this.updatedAt=now;} public UUID getUserId(){return userId;} public long getScoutPoints(){return scoutPoints;} public long getPredictionsCount(){return predictionsCount;} public long getSuccessfulPredictions(){return successfulPredictions;} public long getFailedPredictions(){return failedPredictions;} public long getExpiredPredictions(){return expiredPredictions;} public int getCurrentSuccessStreak(){return currentSuccessStreak;} public int getBestSuccessStreak(){return bestSuccessStreak;} public Double accuracy(){long d=successfulPredictions+failedPredictions;return d==0?null:(double)successfulPredictions/d;} public void predictionCreated(Instant now){predictionsCount++;updatedAt=now;} public void success(int points,Instant now){scoutPoints+=points;successfulPredictions++;currentSuccessStreak++;bestSuccessStreak=Math.max(bestSuccessStreak,currentSuccessStreak);lastResolvedPredictionAt=now;updatedAt=now;} public void failed(Instant now){failedPredictions++;currentSuccessStreak=0;lastResolvedPredictionAt=now;updatedAt=now;} public void expired(Instant now){expiredPredictions++;lastResolvedPredictionAt=now;updatedAt=now;} }
